const crypto = require('crypto');
const SIGNING_KEY = 'a4913c9628de30480aa4c4a17fc03617';

const body = $input.first().json.body || $input.first().json;
const sig  = body.signature || {};
const data = body['event-data'] || {};

const computed = crypto
  .createHmac('sha256', SIGNING_KEY)
  .update(String(sig.timestamp) + String(sig.token))
  .digest('hex');
const valid = computed === sig.signature;

const vars = data['user-variables'] || {};
const event_ts_epoch = data.timestamp || (Date.now() / 1000);
const reason = (data['delivery-status'] && data['delivery-status'].message) || data.reason || data.error || null;
const msgid = (data.message && data.message.headers && data.message.headers['message-id']) || null;

return [{
  json: {
    valid,
    event: data.event || 'unknown',
    severity: data.severity || null,
    token: vars.token || null,
    sub_id: vars.sub_id || null,
    doc_type: vars.doc_type || null,
    msgid,
    recipient: data.recipient || null,
    reason,
    event_ts_iso: new Date(event_ts_epoch * 1000).toISOString(),
    event_ts_epoch
  }
}];

